def build_prompt(persona: dict, session_topic: str, session_idx: int) -> str:
    """Build the generator prompt for one session. Deterministic given persona + topic."""
    style = persona["communication_style"]
    preferences = persona["preferences_concrete"]
    signature = ", ".join(style.get("signature_phrases", [])[:5]) or "(none)"
    vocab = ", ".join(style.get("vocabulary_markers", [])[:10]) or "(none)"
    dislikes = ", ".join(preferences.get("hates", [])[:5]) or "(none)"
    return f"""Generate a realistic text-message session for a specific persona.

Persona ID: {persona["id"]}
Name: {persona["name"]}, {persona["age"]}yo, {persona["occupation"]}
Location: {persona["location"]}
Formality: {style["formality_level"]} ({style.get("formality_notes", "")})
Emoji usage: {style["emoji_usage"]} ({style.get("emoji_notes", "")})
Signature phrases: {signature}
Vocabulary markers: {vocab}
Dislikes: {dislikes}

Session {session_idx + 1}/30 — scenario: {session_topic}

Constraints:
  • Produce 8–12 messages in this one session, representing what {persona["name"]} would TYPE — first-person, messaging-app register.
  • Stay in the persona's formality and emoji register throughout.
  • At least 2 messages must reference something from the persona's interests / notable facts.
  • Do NOT produce AI-assistant turns, or describe the scene. Only the persona's messages.
  • Do NOT include meta-commentary, disclaimers, or system text.
  • Separate each message on its own line.

Output ONLY the messages, one per line, no numbering.
""".strip()


def estimate_cost(num_personas: int, sessions_per: int, output_tokens: int = 400) -> float:
    """Rough cost in USD — dual generator, claude-sonnet-4-6 ~$3/1M out, gpt-4.1-mini ~$0.60/1M out."""
    total_out_tokens = num_personas * sessions_per * 2 * output_tokens  # 2 generators
    # rough: average ~$1.80 per 1M output tokens across the two models, plus input ~equal
    return total_out_tokens * 1.8e-6 + total_out_tokens * 1.0e-6


def main() -> int:
    parser = argparse.ArgumentParser()
    parser.add_argument("--live", action="store_true",
                        help="Actually call the API (otherwise dry-run)")
    parser.add_argument("--sessions-per-persona", type=int, default=30)
    parser.add_argument("--seed", type=int, default=42)
    args = parser.parse_args()

    personas_path = DATASETS / "l0_personas.json"
    if not personas_path.exists():
        print(f"ERROR: {personas_path} not found", file=sys.stderr)
        return 1
    personas_data = json.loads(personas_path.read_text())
    personas = {p["id"]: p for p in personas_data["personas"]}

    random.seed(args.seed)

    total_sessions = len(personas) * args.sessions_per_persona
    cost_usd = estimate_cost(len(personas), args.sessions_per_persona)

    print(f"L0 multi-persona transcript generator")
    print(f"  Personas:        {len(personas)}  ({', '.join(personas)})")
    print(f"  Sessions each:   {args.sessions_per_persona}")
    print(f"  Total sessions:  {total_sessions}")
    print(f"  Generators:      claude-sonnet-4-6 (primary), gpt-4.1-mini (secondary)")
    print(f"  Estimated cost:  ${cost_usd:.2f}")
    print(f"  Output path:     {OUT}")
    print(f"  Seed:            {args.seed}")
    print()

    if not args.live:
        print("DRY RUN — no API calls. Previewing first prompt for each persona:\n")
        for pid, persona in personas.items():
            topic = SESSION_TEMPLATES[pid][0]
            prompt = build_prompt(persona, topic, 0)
            print(f"=== {pid} session 1 of {args.sessions_per_persona} ===")
            print(prompt)
            print()
        print(f"To run for real: python {Path(__file__).name} --live")
        return 0

    # Live mode — requires OPENAI_API_KEY and ANTHROPIC_API_KEY
    for k in ("OPENAI_API_KEY", "ANTHROPIC_API_KEY"):
        if not os.environ.get(k):
            print(f"ERROR: {k} not set in environment", file=sys.stderr)
            return 2

    # Lazy imports so dry-run doesn't require these libraries
    try:
        import anthropic
        import openai
    except ImportError as exc:
        print(f"ERROR: pip install anthropic openai  ({exc})", file=sys.stderr)
        return 3

    anthropic_client = anthropic.Anthropic()
    openai_client = openai.OpenAI()

    sessions_out: list[dict] = []
    rejected = 0

    for pid, persona in personas.items():
        templates = SESSION_TEMPLATES[pid][:args.sessions_per_persona]
        if len(templates) < args.sessions_per_persona:
            print(f"WARN: {pid} has only {len(templates)} templates, requested {args.sessions_per_persona}")
        for idx, topic in enumerate(templates):
            prompt = build_prompt(persona, topic, idx)
            variants: dict[str, list[str]] = {}

            # Anthropic
            try:
                resp = anthropic_client.messages.create(
                    model="claude-sonnet-4-5-20250929",
                    max_tokens=1500,
                    messages=[{"role": "user", "content": prompt}],
                )
                text = resp.content[0].text.strip()
                msgs = [ln.strip() for ln in text.split("\n") if ln.strip()]
                variants["anthropic"] = msgs
            except Exception as exc:
                print(f"  {pid} s{idx}: anthropic FAILED — {exc}", file=sys.stderr)

            # OpenAI
            try:
                resp = openai_client.chat.completions.create(
                    model="gpt-4.1-mini",
                    temperature=0.7,
                    messages=[{"role": "user", "content": prompt}],
                )
                text = resp.choices[0].message.content.strip()
                msgs = [ln.strip() for ln in text.split("\n") if ln.strip()]
                variants["openai"] = msgs
            except Exception as exc:
                print(f"  {pid} s{idx}: openai FAILED — {exc}", file=sys.stderr)

            # Keep only if BOTH generators returned ≥5 messages
            if not (len(variants.get("anthropic", [])) >= 5 and len(variants.get("openai", [])) >= 5):
                rejected += 1
                print(f"  {pid} s{idx}: REJECTED (insufficient coverage)")
                continue

            # We keep the claude variant as the authoritative transcript (primary)
            # but record both generators for provenance.
            sessions_out.append({
                "session_id": f"{pid}_s{idx:02d}",
                "persona_id": pid,
                "topic": topic,
                "messages": variants["anthropic"],
                "alternate_openai_sample": variants["openai"][:3],  # store 3 samples for audit
                "models": ["anthropic/claude-sonnet-4-5", "openai/gpt-4.1-mini"],
            })
            if idx % 5 == 0:
                print(f"  {pid} s{idx}: ok ({len(variants['anthropic'])} msgs)")

    out_payload = {
        "meta": {
            "version": "1.0",
            "generated_at": time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime()),
            "sessions_kept": len(sessions_out),
            "sessions_rejected": rejected,
            "generators": ["anthropic/claude-sonnet-4-5", "openai/gpt-4.1-mini"],
            "acceptance_rule": "both generators must produce ≥5 lines",
        },
        "sessions": sessions_out,
    }
    OUT.write_text(json.dumps(out_payload, indent=2, ensure_ascii=False))
    print(f"\nWrote {len(sessions_out)} sessions to {OUT}")
    return 0


if __name__ == "__main__":
    sys.exit(main())
